use proptest::prelude::*;

const MAX_VAULT_TVL: u64 = 10000000000000000;

#[derive(Debug, Clone, Copy)]
struct State {
    V: u128,
    C_tot: u128,
    I: u128,
}

/// Proptest strategy for generating arbitrary State values.
fn arb_state() -> impl Strategy<Value = State> {
    (
        0u128..=10000000000000000u128,
        0u128..=10000000000000000u128,
        0u128..=10000000000000000u128,
    ).prop_map(|(V, C_tot, I)| State {
        V,
        C_tot,
        I,
    })
}

/// Boundary-biased strategy for guard rejection tests.
fn arb_boundary_state() -> impl Strategy<Value = State> {
    (
        prop_oneof![0u128..=3u128, (10000000000000000 - 3)..=10000000000000000u128],
        prop_oneof![0u128..=3u128, (10000000000000000 - 3)..=10000000000000000u128],
        prop_oneof![0u128..=3u128, (10000000000000000 - 3)..=10000000000000000u128],
    ).prop_map(|(V, C_tot, I)| State {
        V,
        C_tot,
        I,
    })
}

/// conservation: s.V ≥ s.C_tot + s.I
fn conservation(s: &State) -> bool {
    s.V >= s.C_tot.wrapping_add(s.I)
}

/// vault_bounded: s.V ≤ 10000000000000000
fn vault_bounded(s: &State) -> bool {
    s.V <= 10000000000000000
}

/// User adds capital — V and C_tot increase by same amount
fn deposit(s: &mut State, amount: u128) -> bool {
    if !(s.V.wrapping_add(amount) <= 10000000000000000) {
        return false;
    }
    s.V = s.V.wrapping_add(amount);
    s.C_tot = s.C_tot.wrapping_add(amount);
    true
}

/// User removes capital — V and C_tot decrease by same amount
fn withdraw(s: &mut State, amount: u128) -> bool {
    if !(s.C_tot >= amount) {
        return false;
    }
    s.V = s.V.wrapping_sub(amount);
    s.C_tot = s.C_tot.wrapping_sub(amount);
    true
}

/// External deposit into insurance fund
fn top_up_insurance(s: &mut State, amount: u128) -> bool {
    if !(s.V.wrapping_add(amount) <= 10000000000000000) {
        return false;
    }
    s.V = s.V.wrapping_add(amount);
    s.I = s.I.wrapping_add(amount);
    true
}

/// Begin auto-deleveraging cycle
fn trigger_adl(s: &mut State) -> bool {
    true
}

/// Complete the drain phase of ADL
fn complete_drain(s: &mut State) -> bool {
    true
}

/// Reset risk engine after ADL cycle
fn reset(s: &mut State) -> bool {
    true
}

